// ─────────────────────────────────────────────
//  components/PostList.js
//  Renders all blog posts fetched from the API
// ─────────────────────────────────────────────
import React from 'react';

// Helper: formats "2024-01-15T10:30:00Z" → "January 15, 2024"
const formatDate = (dateString) =>
  new Date(dateString).toLocaleDateString('en-US', {
    year: 'numeric', month: 'long', day: 'numeric',
  });

const PostList = ({ posts, loading, error }) => {
  if (loading) {
    return (
      <section className="posts-section">
        <div className="loading-state">
          <div className="spinner" />
          <p>Loading posts…</p>
        </div>
      </section>
    );
  }

  if (error) {
    return (
      <section className="posts-section">
        <p className="error-msg">{error}</p>
      </section>
    );
  }

  return (
    <section className="posts-section">
      <h2 className="section-title">
        <span className="title-accent">✦</span> All Posts
        <span className="post-count">{posts.length}</span>
      </h2>

      {posts.length === 0 ? (
        <div className="empty-state">
          <p>No posts yet. Be the first to write something!</p>
        </div>
      ) : (
        <div className="posts-grid">
          {posts.map((post, index) => (
            <article
              key={post._id}
              className="post-card"
              style={{ animationDelay: `${index * 60}ms` }}
            >
              {/* Post number badge */}
              <span className="post-number">#{posts.length - index}</span>

              <h3 className="post-title">{post.title}</h3>

              <p className="post-content">{post.content}</p>

              <footer className="post-footer">
                <time className="post-date" dateTime={post.createdAt}>
                  {formatDate(post.createdAt)}
                </time>
              </footer>
            </article>
          ))}
        </div>
      )}
    </section>
  );
};

export default PostList;
